document.addEventListener("DOMContentLoaded",()=>{const greetingEl=document.querySelector(".section-greeting");if(greetingEl){const hours=new Date().getHours();const greeting=hours<12?"Bonjour":hours<18?"Bonne après-midi":"Bonsoir";greetingEl.textContent=greeting}
const menuLinks=document.querySelectorAll(".profile-menu .menu-links a");const sections=document.querySelectorAll(".profile-content > .profile-section",);function showSection(targetId){sections.forEach((s)=>{s.classList.remove("active");s.style.display="none"});const target=document.getElementById(targetId);if(target){target.style.display="block";target.offsetHeight;target.classList.add("active")}}
function setActiveLink(link){menuLinks.forEach((l)=>l.classList.remove("active"));link.classList.add("active")}
const defaultSection=document.querySelector(".profile-section.active");if(defaultSection){sections.forEach((s)=>{if(s!==defaultSection)s.style.display="none"})}
menuLinks.forEach((link)=>{link.addEventListener("click",(e)=>{e.preventDefault();const targetId=link.getAttribute("data-section");if(!targetId)return;showSection(targetId);setActiveLink(link)})});const btnEditToggle=document.getElementById("btn-edit-toggle");const btnCancelEdit=document.getElementById("btn-cancel-edit");const btnCancelEdit2=document.getElementById("btn-cancel-edit-2");const profileView=document.getElementById("profile-view");const profileEdit=document.getElementById("profile-edit");function showEdit(){if(!profileView||!profileEdit)return;profileView.style.display="none";profileEdit.style.display="block";btnEditToggle.innerHTML='<i class="fas fa-eye"></i> Voir';profileEdit.scrollIntoView({behavior:"smooth",block:"start"})}
function showView(){if(!profileView||!profileEdit)return;profileEdit.style.display="none";profileView.style.display="block";btnEditToggle.innerHTML='<i class="fas fa-pen"></i> Modifier'}
btnEditToggle?.addEventListener("click",showEdit);btnCancelEdit?.addEventListener("click",showView);btnCancelEdit2?.addEventListener("click",showView);document.getElementById("profile_picture")?.addEventListener("change",(e)=>{const file=e.target.files[0];if(!file)return;if(file.size>5*1024*1024){alert("L'image ne doit pas dépasser 5 Mo.");e.target.value="";return}
const reader=new FileReader();reader.onload=(ev)=>{document.getElementById("avatar-preview").src=ev.target.result};reader.readAsDataURL(file)});document.getElementById("profile-edit-form")?.addEventListener("submit",async(e)=>{e.preventDefault();const btn=document.getElementById("btn-save");const msgBox=document.getElementById("edit-message");const btnText=btn.querySelector(".btn-text");const spinner=btn.querySelector(".btn-spinner");document.querySelectorAll(".edit-error").forEach((el)=>(el.textContent=""));msgBox.style.display="none";msgBox.className="edit-message";btn.disabled=!0;btnText.style.display="none";spinner.style.display="flex";try{const res=await fetch("./profile/update",{method:"POST",body:new FormData(e.target),headers:{"X-Requested-With":"XMLHttpRequest"},});const data=await res.json();if(data.success){msgBox.textContent=data.message??"Profil mis à jour avec succès.";msgBox.classList.add("success");msgBox.style.display="block";if(data.user){const fieldMap={username:'[data-field="username"]',fullname:'[data-field="fullname"]',email:'[data-field="email"]',phone_number:'[data-field="phone"]',country:'[data-field="country"]',bio:'[data-field="bio"]',birth_date:'[data-field="birth_date"]',english_level:'[data-field="english_level"]',};Object.entries(fieldMap).forEach(([key,selector])=>{const el=document.querySelector(selector);if(el&&data.user[key]!==undefined){el.textContent=data.user[key]||"Non renseigné"}});if(data.user.profile_picture){const newSrc="../public/uploads/profiles/"+data.user.profile_picture+"?t="+Date.now();document.querySelectorAll(".avatar, .edit-avatar-preview").forEach((img)=>{img.src=newSrc})}
if(data.user.english_level){const levelLabels={beginner:"Débutant",intermediate:"Intermédiaire",advanced:"Avancé",};const levelBadge=document.querySelector(".level-badge");if(levelBadge){levelBadge.innerHTML=`<i class="fas fa-graduation-cap"></i> ${levelLabels[data.user.english_level] ?? data.user.english_level}`}}
const sidebarUsername=document.querySelector(".menu-header h2");if(sidebarUsername&&data.user.username){sidebarUsername.textContent=data.user.username}}
setTimeout(()=>showView(),1500)}else{if(data.errors){Object.entries(data.errors).forEach(([field,msg])=>{const el=document.getElementById("err-"+field);if(el)el.textContent=msg})}
msgBox.textContent=data.message??"Une erreur est survenue.";msgBox.classList.add("error");msgBox.style.display="block"}}catch(err){msgBox.textContent="Erreur réseau. Veuillez réessayer.";msgBox.classList.add("error");msgBox.style.display="block"}finally{btn.disabled=!1;btnText.style.display="flex";spinner.style.display="none"}});document.querySelector(".btn-setting.logout")?.addEventListener("click",()=>{window.location.href="./logout"})})